// Read and parse Deck.json using require('fs')
const fs = require('fs');
const deckPath = $('Set Global Parameters').first().json.DeckJsonPath;
const raw = fs.readFileSync(deckPath.replace(/\//g, '\\'), 'utf8').replace(/^\uFEFF/, '');
const data = JSON.parse(raw);
return [{ json: { data } }];

// ============================================================
// Build 3D Object Job List
// ============================================================
// Reads each card JSON and builds jobs for the Hunyuan3D v2.1
// pipeline: Upscale → BG Removal → Hunyuan3D → Refine.
// Falls back to TripoSR if Hunyuan3D fails or is disabled.
// ============================================================

const fs = require('fs');
const path = require('path');

const params = $('Set Global Parameters').first().json;
const testCardFilter = (params.TestCardFilter || '').trim();
const orientations = (params.Orientations || 'upright,reversed,between').split(',').map(s => s.trim());
const skipExisting = params.SkipExisting !== 'false';

const raw = $input.first().json;
const deck = raw.data !== undefined ? raw.data : raw;

const deckDir = ((deck.Assets && deck.Assets.Directory)
  ? deck.Assets.Directory
  : 'D:/data/cards/Standard').replace(/\//g, path.sep);

// Read 3D settings from Deck.json with safe defaults
const models3D = (deck.Models && deck.Models['3D']) || {};
const samplers3D = (deck.Samplers && deck.Samplers['3D']) || {};

// FIX: Read Hunyuan3D settings from Samplers.Hunyuan3D (sibling of Samplers.3D)
const h3dSettings = (deck.Samplers && deck.Samplers.Hunyuan3D) || {};

// Model references
const upscaleModel = models3D.UpscaleModel || 'RealESRGAN_x4plus.pth';
const hunyuan3DCheckpoint = models3D.Hunyuan3DCheckpoint || 'hunyuan_3d_v2.1.safetensors';
const birefnetModel = models3D.BiRefNetModel || 'BiRefNet-general';

// TripoSR fallback settings (from Samplers.3D)
const tripoResolution = Math.min(samplers3D.Resolution || 256, 512);
const tripoThreshold = samplers3D.Threshold || 15.0;
const tripoChunkSize = Math.min(samplers3D.ChunkSize || 8192, 10000);

const cardRefs = deck.Cards;
if (!cardRefs || cardRefs.length === 0) {
  throw new Error('[Build 3D Job List] No Cards found in Deck.json.');
}

const filteredCards = testCardFilter
  ? cardRefs.filter(c => c.Card === testCardFilter)
  : cardRefs;

if (filteredCards.length === 0) {
  throw new Error('[Build 3D Job List] No cards matched filter: ' + JSON.stringify(testCardFilter));
}

const jobs = [];
const skippedNoImage = [];

for (const cardRef of filteredCards) {
  const cardName = cardRef.Card;
  const cardSlug = cardName.replace(/[()]/g, '').replace(/\s+/g, '_');
  const cardFilePath = path.join(deckDir, cardRef.File.replace(/\//g, path.sep));

  let cardRaw;
  try {
    cardRaw = JSON.parse(fs.readFileSync(cardFilePath, 'utf8').replace(/^\uFEFF/, ''));
  } catch(e) {
    console.warn('[Build 3D Job List] Cannot read card: ' + cardName + ': ' + e.message);
    continue;
  }

  const card = cardRaw['data.Cards'] || cardRaw;
  const cardDir = (card.Directory || path.join(deckDir, 'Cards')).replace(/\//g, path.sep);
  const records = card.records || [];

  for (const orientation of orientations) {
    const record = records.find(r => r.Orientation === orientation);
    if (!record) continue;

    const glbFilename = 'MODEL_' + cardSlug + '_' + orientation + '.glb';
    const glbPath = path.join(cardDir, glbFilename);

    if (skipExisting && fs.existsSync(glbPath)) {
      continue;
    }

    // Source card image — use IMG_ prefix, try multiple case variants
    let cardImgFilename = null;
    let cardImgPath = null;
    const orientCaps = orientation.charAt(0).toUpperCase() + orientation.slice(1);
    const imgCandidates = [
      'IMG_' + cardSlug + '_' + orientCaps + '.png',
      'IMG_' + cardSlug + '_' + orientation + '.png',
      'IMG_' + cardSlug + '_' + orientation.toUpperCase() + '.png'
    ];
    for (const candidate of imgCandidates) {
      const candidatePath = path.join(cardDir, candidate);
      if (fs.existsSync(candidatePath)) {
        cardImgFilename = candidate;
        cardImgPath = candidatePath;
        break;
      }
    }
    if (!cardImgFilename) {
      skippedNoImage.push(cardName + ' ' + orientation + ' (tried: ' + imgCandidates.join(', ') + ')');
      continue;
    }

    // Intermediate filenames (insertable assets)
    const upscaledFilename = 'UPSCALED_' + cardSlug + '_' + orientation + '.png';
    const upscaledPath = path.join(cardDir, upscaledFilename);
    const noBgFilename = 'NOBG_' + cardSlug + '_' + orientation + '.png';
    const noBgPath = path.join(cardDir, noBgFilename);

    // Detect existing insertable assets
    const noBgExists = fs.existsSync(noBgPath);
    const upscaledExists = fs.existsSync(upscaledPath);

    jobs.push({
      CardName: cardName,
      CardSlug: cardSlug,
      Orientation: orientation,
      CardDir: cardDir,
      CardFilePath: cardFilePath,
      SourceImagePath: cardImgPath,
      SourceImageFilename: cardImgFilename,
      GLBFilename: glbFilename,
      OBJFilename: 'MODEL_' + cardSlug + '_' + orientation + '.obj',
      RefFilename: '3DREF_' + cardSlug + '_' + orientation + '.png',
      // Model references
      UpscaleModel: upscaleModel,
      Hunyuan3DCheckpoint: hunyuan3DCheckpoint,
      BiRefNetModel: birefnetModel,
      // Stage A intermediates
      UpscaledFilename: upscaledFilename,
      UpscaledPath: upscaledPath,
      UpscaledExists: upscaledExists,
      NoBgFilename: noBgFilename,
      NoBgPath: noBgPath,
      NoBgExists: noBgExists,
      // Hunyuan3D sampler settings (from Deck.json Samplers.Hunyuan3D)
      H3DLatentRes: h3dSettings.LatentResolution || 3072,
      H3DSteps: h3dSettings.Steps || 30,
      H3DCFG: h3dSettings.CFG || 5.5,
      H3DSampler: h3dSettings.Sampler || 'euler',
      H3DScheduler: h3dSettings.Scheduler || 'sgm_uniform',
      H3DOctreeRes: h3dSettings.OctreeResolution || 256,
      H3DNumChunks: h3dSettings.NumChunks || 8000,
      H3DMeshAlgo: h3dSettings.MeshAlgorithm || 'surface net',
      H3DMeshThreshold: h3dSettings.MeshThreshold || 0.6,
      // TripoSR fallback settings
      TripoResolution: tripoResolution,
      TripoThreshold: tripoThreshold,
      TripoChunkSize: tripoChunkSize
    });
  }
}

if (skippedNoImage.length > 0) {
  console.warn('[Build 3D Job List] Skipped ' + skippedNoImage.length + ' cards with no source image:');
  for (const s of skippedNoImage.slice(0, 10)) {
    console.warn('  - ' + s);
  }
}

if (jobs.length === 0) {
  throw new Error('[Build 3D Job List] No jobs created. Check card images (IMG_ prefix) exist and SkipExisting settings.');
}

console.warn('[Build 3D Job List] Created ' + jobs.length + ' jobs');
return jobs.map(j => ({ json: j }));

// ============================================================
// Upscale & Prep Source Images (Stage A)
// ============================================================
// For each job, upscales source card image 4x with RealESRGAN,
// then removes background with BiRefNet. Outputs UPSCALED_ and
// NOBG_ images. Skips if NOBG already exists (insertable asset).
// Clears VRAM after all jobs via POST /free.
// ============================================================

const http = require('http');
const fs = require('fs');
const path = require('path');

const httpRequest = (method, urlStr, body) => new Promise((resolve, reject) => {
  const m = urlStr.match(/^(https?):\/\/([^:/]+)(?::(\d+))?(\/?[^?]*)(\?.*)?$/);
  if (!m) return reject(new Error('Bad URL: ' + urlStr));
  const options = { hostname: m[2], port: m[3] ? parseInt(m[3]) : 80, path: (m[4] || '/') + (m[5] || ''), method, headers: {} };
  if (body) { options.headers['Content-Type'] = 'application/json'; options.headers['Content-Length'] = Buffer.byteLength(body); }
  const req = http.request(options, (res) => {
    let data = '';
    res.on('data', (chunk) => { data += chunk; });
    res.on('end', () => { try { resolve(JSON.parse(data)); } catch(e) { resolve(data); } });
  });
  req.on('error', reject);
  if (body) req.write(body);
  req.end();
});
const httpPost = (url, obj) => httpRequest('POST', url, JSON.stringify(obj));
const httpGet  = (url)      => httpRequest('GET',  url, null);
const sleep = ms => new Promise(r => setTimeout(r, ms));

const params = $('Set Global Parameters').first().json;
const comfyAPI = (params.ComfyUIAPI || 'http://127.0.0.1:8188').replace(/\/$/, '');
const skipExisting = params.SkipExisting !== 'false';
const comfyInputDir = 'D:/ComfyUI_windows_portable/ComfyUI/input';
const comfyOutputDir = 'D:/ComfyUI_windows_portable/ComfyUI/output';

const allJobs = $input.all().map(item => item.json);
const results = [];

for (let idx = 0; idx < allJobs.length; idx++) {
  const job = allJobs[idx];

  if (skipExisting && job.NoBgExists) {
    console.warn('[Stage A] (' + (idx+1) + '/' + allJobs.length + ') NOBG exists, skipping: ' + job.CardName + ' ' + job.Orientation);
    results.push({ ...job, StageAStatus: 'exists' });
    continue;
  }

  console.warn('[Stage A] (' + (idx+1) + '/' + allJobs.length + ') Upscale+BG removal: ' + job.CardName + ' ' + job.Orientation);

  // Copy source image to ComfyUI input
  try {
    fs.copyFileSync(job.SourceImagePath, path.join(comfyInputDir, job.SourceImageFilename));
  } catch(e) {
    results.push({ ...job, StageAStatus: 'failed', StageAReason: 'Copy to input: ' + e.message });
    continue;
  }

  const comfyPrompt = {
    "1": { "class_type": "LoadImage", "inputs": { "image": job.SourceImageFilename }, "_meta": { "title": "Load Card Image" } },
    "2": { "class_type": "UpscaleModelLoader", "inputs": { "model_name": job.UpscaleModel }, "_meta": { "title": "Load RealESRGAN" } },
    "3": { "class_type": "ImageUpscaleWithModel", "inputs": { "upscale_model": ["2", 0], "image": ["1", 0] }, "_meta": { "title": "Upscale 4x" } },
    "4": { "class_type": "BiRefNetRMBG", "inputs": { "image": ["3", 0], "model": job.BiRefNetModel, "mask_blur": 0, "mask_offset": 0, "invert_output": false, "refine_foreground": true, "background": "Alpha", "background_color": "#222222" }, "_meta": { "title": "Remove Background" } },
    "5": { "class_type": "SaveImage", "inputs": { "images": ["4", 0], "filename_prefix": "NOBG_" + job.CardSlug + "_" + job.Orientation }, "_meta": { "title": "Save NOBG" } },
    "6": { "class_type": "SaveImage", "inputs": { "images": ["3", 0], "filename_prefix": "UPSCALED_" + job.CardSlug + "_" + job.Orientation }, "_meta": { "title": "Save Upscaled" } }
  };

  let submitData;
  try { submitData = await httpPost(comfyAPI + '/prompt', { prompt: comfyPrompt }); } catch(e) {
    results.push({ ...job, StageAStatus: 'failed', StageAReason: 'Submit: ' + e.message }); continue;
  }
  if (submitData.error) { results.push({ ...job, StageAStatus: 'failed', StageAReason: 'ComfyUI: ' + JSON.stringify(submitData.error).substring(0, 300) }); continue; }
  const promptId = submitData.prompt_id;
  if (!promptId) { results.push({ ...job, StageAStatus: 'failed', StageAReason: 'No prompt_id' }); continue; }

  // Poll for completion (up to 10 min)
  let done = false;
  for (let attempt = 0; attempt < 120 && !done; attempt++) {
    await sleep(5000);
    try {
      const hist = await httpGet(comfyAPI + '/history/' + promptId);
      const entry = hist[promptId];
      if (!entry) continue;
      if (entry.status && entry.status.completed) {
        if (entry.status.status_str === 'error') {
          results.push({ ...job, StageAStatus: 'failed', StageAReason: 'Execution error' }); done = true; continue;
        }
        // Copy outputs to card directory
        const outputFiles = fs.readdirSync(comfyOutputDir);
        const nobgPrefix = 'NOBG_' + job.CardSlug + '_' + job.Orientation;
        const upPrefix = 'UPSCALED_' + job.CardSlug + '_' + job.Orientation;
        const nobgMatch = outputFiles.filter(f => f.startsWith(nobgPrefix) && f.endsWith('.png')).sort().reverse();
        const upMatch = outputFiles.filter(f => f.startsWith(upPrefix) && f.endsWith('.png')).sort().reverse();
        fs.mkdirSync(job.CardDir, { recursive: true });
        if (nobgMatch.length > 0) {
          fs.copyFileSync(path.join(comfyOutputDir, nobgMatch[0]), job.NoBgPath);
          // Also copy to ComfyUI input for Stage B
          fs.copyFileSync(path.join(comfyOutputDir, nobgMatch[0]), path.join(comfyInputDir, job.NoBgFilename));
        }
        if (upMatch.length > 0) {
          fs.copyFileSync(path.join(comfyOutputDir, upMatch[0]), job.UpscaledPath);
        }
        results.push({ ...job, StageAStatus: 'generated', NoBgExists: true, UpscaledExists: true });
        done = true;
      }
    } catch(e) { if (attempt % 12 === 0) console.warn('[Stage A] Poll ' + attempt + ': ' + e.message); }
  }
  if (!done) results.push({ ...job, StageAStatus: 'timeout' });
}

// Free VRAM between stages
try { await httpPost(comfyAPI + '/free', { unload_models: true, free_memory: true }); await sleep(2000); } catch(e) {}

const gen = results.filter(r => r.StageAStatus === 'generated').length;
const exi = results.filter(r => r.StageAStatus === 'exists').length;
const fail = results.filter(r => r.StageAStatus === 'failed').length;
console.warn('[Stage A] Done: ' + gen + ' generated, ' + exi + ' existed, ' + fail + ' failed');
return results.map(r => ({ json: r }));

// ============================================================
// Generate 3D Models (Stage C)
// ============================================================
// For each job, generates a 3D mesh using:
//   Tier 1: Hunyuan3D v2.1 single-view (from NOBG image)
//   Tier 2: TripoSR fallback if Hunyuan3D fails or disabled
// Clears VRAM via POST /free after each card.
// ============================================================

const http = require('http');
const fs = require('fs');
const path = require('path');

const httpRequest = (method, urlStr, body) => new Promise((resolve, reject) => {
  const m = urlStr.match(/^(https?):\/\/([^:/]+)(?::(\d+))?(\/?[^?]*)(\?.*)?$/);
  if (!m) return reject(new Error('Bad URL: ' + urlStr));
  const options = { hostname: m[2], port: m[3] ? parseInt(m[3]) : 80, path: (m[4] || '/') + (m[5] || ''), method, headers: {} };
  if (body) { options.headers['Content-Type'] = 'application/json'; options.headers['Content-Length'] = Buffer.byteLength(body); }
  const req = http.request(options, (res) => {
    let data = '';
    res.on('data', (chunk) => { data += chunk; });
    res.on('end', () => { try { resolve(JSON.parse(data)); } catch(e) { resolve(data); } });
  });
  req.on('error', reject);
  if (body) req.write(body);
  req.end();
});
const httpPost = (url, obj) => httpRequest('POST', url, JSON.stringify(obj));
const httpGet  = (url)      => httpRequest('GET',  url, null);
const sleep = ms => new Promise(r => setTimeout(r, ms));

const params = $('Set Global Parameters').first().json;
const comfyAPI = (params.ComfyUIAPI || 'http://127.0.0.1:8188').replace(/\/$/, '');
const hunyuan3DEnabled = params.Hunyuan3DEnabled !== 'false';
const comfyInputDir = 'D:/ComfyUI_windows_portable/ComfyUI/input';
const comfyOutputDir = 'D:/ComfyUI_windows_portable/ComfyUI/output';

// Free VRAM before starting
try { await httpPost(comfyAPI + '/free', { unload_models: true, free_memory: true }); await sleep(2000); } catch(e) {}

const allJobs = $input.all().map(item => item.json);
const results = [];

for (let idx = 0; idx < allJobs.length; idx++) {
  const job = allJobs[idx];
  console.warn('[Stage C] (' + (idx+1) + '/' + allJobs.length + ') ' + job.CardName + ' ' + job.Orientation);

  let generated = false;

  // ------- Tier 1: Hunyuan3D v2.1 single-view -------
  if (hunyuan3DEnabled && !generated) {
    const genMethod = 'hunyuan3d_singleview';

    // Use NOBG image, fallback to source image
    const singleImg = job.NoBgFilename;
    const singleInInput = path.join(comfyInputDir, singleImg);
    if (!fs.existsSync(singleInInput) && fs.existsSync(job.NoBgPath)) {
      fs.copyFileSync(job.NoBgPath, singleInInput);
    }
    // Fallback: copy source image if NOBG not available
    if (!fs.existsSync(singleInInput)) {
      const srcInInput = path.join(comfyInputDir, job.SourceImageFilename);
      if (!fs.existsSync(srcInInput)) {
        fs.copyFileSync(job.SourceImagePath, srcInInput);
      }
    }
    const inputImg = fs.existsSync(singleInInput) ? singleImg : job.SourceImageFilename;
    console.warn('[Stage C] Using input: ' + inputImg);

    const comfyPrompt = {
      "1":  { "class_type": "unCLIPCheckpointLoader", "inputs": { "ckpt_name": job.Hunyuan3DCheckpoint }, "_meta": { "title": "Load Hunyuan3D v2.1" } },
      "2":  { "class_type": "LoadImage", "inputs": { "image": inputImg }, "_meta": { "title": "Load Front View" } },
      "3":  { "class_type": "CLIPVisionEncode", "inputs": { "clip_vision": ["1", 3], "image": ["2", 0], "crop": "center" }, "_meta": { "title": "Encode Image" } },
      "4":  { "class_type": "Hunyuan3Dv2Conditioning", "inputs": { "clip_vision_output": ["3", 0] }, "_meta": { "title": "Hunyuan3D Conditioning" } },
      "5":  { "class_type": "EmptyLatentHunyuan3Dv2", "inputs": { "resolution": job.H3DLatentRes, "batch_size": 1 }, "_meta": { "title": "Empty 3D Latent" } },
      "6":  { "class_type": "KSampler", "inputs": { "model": ["1", 0], "positive": ["4", 0], "negative": ["4", 1], "latent_image": ["5", 0], "seed": Math.floor(Math.random() * 2147483647), "steps": job.H3DSteps, "cfg": job.H3DCFG, "sampler_name": job.H3DSampler, "scheduler": job.H3DScheduler, "denoise": 1.0 }, "_meta": { "title": "KSampler" } },
      "7":  { "class_type": "VAEDecodeHunyuan3D", "inputs": { "samples": ["6", 0], "vae": ["1", 2], "num_chunks": job.H3DNumChunks, "octree_resolution": job.H3DOctreeRes }, "_meta": { "title": "Decode 3D Voxels" } },
      "8":  { "class_type": "VoxelToMesh", "inputs": { "voxel": ["7", 0], "algorithm": job.H3DMeshAlgo, "threshold": job.H3DMeshThreshold }, "_meta": { "title": "Voxel to Mesh" } },
      "9":  { "class_type": "SaveGLB", "inputs": { "mesh": ["8", 0], "filename_prefix": "MODEL_" + job.CardSlug + "_" + job.Orientation }, "_meta": { "title": "Save GLB" } }
    };

    try {
      const submitData = await httpPost(comfyAPI + '/prompt', { prompt: comfyPrompt });
      if (submitData.error) throw new Error('ComfyUI reject: ' + JSON.stringify(submitData.error).substring(0, 300));
      const promptId = submitData.prompt_id;
      if (!promptId) throw new Error('No prompt_id returned');

      console.warn('[Stage C] Submitted Hunyuan3D prompt: ' + promptId);

      // Poll for completion (up to 60 min)
      let done = false;
      for (let attempt = 0; attempt < 720 && !done; attempt++) {
        await sleep(5000);
        try {
          const hist = await httpGet(comfyAPI + '/history/' + promptId);
          const entry = hist[promptId];
          if (!entry) continue;

          const statusStr = entry.status ? entry.status.status_str : null;
          if (statusStr === 'error') {
            const errMsgs = (entry.status.messages || []).filter(m => m[0] === 'execution_error');
            const errDetail = errMsgs.length > 0 ? JSON.stringify(errMsgs[0][1]).substring(0, 400) : 'Unknown execution error';
            throw new Error(errDetail);
          }
          if (statusStr === 'success') {
            results.push({ ...job, Status: 'generated', GenerationMethod: genMethod, PromptId: promptId });
            generated = true;
            done = true;
            console.warn('[Stage C] Hunyuan3D success: ' + job.CardName + ' ' + job.Orientation);
          }
        } catch(e) {
          if (e.message.includes('error') || e.message.includes('ComfyUI')) throw e;
          if (attempt % 24 === 0) console.warn('[Stage C] Poll ' + attempt + ': ' + e.message);
        }
      }
      if (!done) throw new Error('Timeout after 60 min');
    } catch(e) {
      console.warn('[Stage C] Hunyuan3D failed: ' + e.message.substring(0, 300));
    }

    // Free VRAM after Hunyuan3D attempt
    try { await httpPost(comfyAPI + '/free', { unload_models: true, free_memory: true }); await sleep(2000); } catch(e) {}
  }

  // ------- Tier 2: TripoSR fallback -------
  if (!generated) {
    console.warn('[Stage C] Falling back to TripoSR for ' + job.CardName + ' ' + job.Orientation);

    // Copy source image to ComfyUI input
    const srcInInput = path.join(comfyInputDir, job.SourceImageFilename);
    if (!fs.existsSync(srcInInput)) {
      try {
        fs.copyFileSync(job.SourceImagePath, srcInInput);
      } catch(e) {
        results.push({ ...job, Status: 'failed', GenerationMethod: 'triposr_failed', Reason: 'Copy: ' + e.message });
        continue;
      }
    }

    const tripoPrompt = {
      "1": { "class_type": "LoadImage", "inputs": { "image": job.SourceImageFilename }, "_meta": { "title": "Load Card Image" } },
      "2": { "class_type": "BiRefNetRMBG", "inputs": { "image": ["1", 0], "model": job.BiRefNetModel, "mask_blur": 0, "mask_offset": 0, "invert_output": false, "refine_foreground": true, "background": "Alpha", "background_color": "#222222" }, "_meta": { "title": "Remove Background" } },
      "3": { "class_type": "SaveImage", "inputs": { "filename_prefix": "3DREF_" + job.CardSlug + "_" + job.Orientation, "images": ["2", 0] }, "_meta": { "title": "Save 3D Ref" } },
      "4": { "class_type": "LoadTripoSRModel_", "inputs": { "chunk_size": job.TripoChunkSize }, "_meta": { "title": "Load TripoSR" } },
      "5": { "class_type": "TripoSRSampler_", "inputs": { "model": ["4", 0], "image": ["2", 0], "resolution": job.TripoResolution, "threshold": job.TripoThreshold, "device": "auto" }, "_meta": { "title": "TripoSR Sampler" } },
      "6": { "class_type": "SaveTripoSRMesh", "inputs": { "mesh": ["5", 0], "filename_prefix": "MODEL_" + job.CardSlug + "_" + job.Orientation }, "_meta": { "title": "Save Mesh" } }
    };

    try {
      const submitData = await httpPost(comfyAPI + '/prompt', { prompt: tripoPrompt });
      if (submitData.error) throw new Error('ComfyUI: ' + JSON.stringify(submitData.error).substring(0, 300));
      const promptId = submitData.prompt_id;
      if (!promptId) throw new Error('No prompt_id');

      let done = false;
      for (let attempt = 0; attempt < 360 && !done; attempt++) {
        await sleep(5000);
        try {
          const hist = await httpGet(comfyAPI + '/history/' + promptId);
          const entry = hist[promptId];
          if (!entry) continue;

          const statusStr = entry.status ? entry.status.status_str : null;
          if (statusStr === 'error') throw new Error('TripoSR execution error');
          if (statusStr === 'success') {
            results.push({ ...job, Status: 'generated', GenerationMethod: 'triposr', PromptId: promptId });
            generated = true;
            done = true;
          }
        } catch(e) {
          if (e.message.includes('error')) throw e;
          if (attempt % 12 === 0) console.warn('[Stage C] TripoSR poll ' + attempt + ': ' + e.message);
        }
      }
      if (!done) throw new Error('TripoSR timeout after 30 min');
    } catch(e) {
      console.warn('[Stage C] TripoSR also failed: ' + e.message.substring(0, 200));
      results.push({ ...job, Status: 'failed', GenerationMethod: 'all_failed', Reason: e.message.substring(0, 300) });
    }

    // Free VRAM after TripoSR
    try { await httpPost(comfyAPI + '/free', { unload_models: true, free_memory: true }); await sleep(2000); } catch(e) {}
  }
}

if (results.length === 0) {
  throw new Error('[Stage C] No results produced. Check ComfyUI is running.');
}

const byMethod = {};
for (const r of results) { byMethod[r.GenerationMethod || 'unknown'] = (byMethod[r.GenerationMethod || 'unknown'] || 0) + 1; }
console.warn('[Stage C] Done: ' + JSON.stringify(byMethod));
return results.map(r => ({ json: r }));

// ============================================================
// Refine 3D Meshes
// ============================================================
// Post-processing on generated GLB files using Python trimesh.
// Writes a batch Python script to temp, runs it ONCE with all
// jobs as JSON input. Uses async spawn (not execFileSync) to keep
// the Node.js event loop alive for task runner heartbeat pings.
//
// trimesh 4.x API: uses nondegenerate_faces() mask instead of
// the removed remove_degenerate_faces/remove_duplicate_faces.
// ============================================================

const fs = require('fs');
const path = require('path');
const { spawn } = require('child_process');
const os = require('os');

const comfyOutputDir = 'D:/ComfyUI_windows_portable/ComfyUI/output';
const allItems = $input.all().map(item => item.json);
const toRefine = [];  // items that need Python refinement
const results = [];   // final output

// --- Phase 1: Copy GLBs from ComfyUI output to card dir (JS, fast) ---
for (let idx = 0; idx < allItems.length; idx++) {
  const item = allItems[idx];
  if (item.Status !== 'generated') { results.push(item); continue; }

  const cardDir = item.CardDir;
  const glbDestPath = path.join(cardDir, item.GLBFilename);
  const prefix = 'MODEL_' + item.CardSlug + '_' + item.Orientation;
  let glbSourcePath = null;

  try {
    const outputFiles = fs.readdirSync(comfyOutputDir);
    const matches = outputFiles.filter(f => f.startsWith(prefix) && f.endsWith('.glb')).sort().reverse();
    if (matches.length > 0) glbSourcePath = path.join(comfyOutputDir, matches[0]);
    if (!glbSourcePath) {
      const meshDir = path.join(comfyOutputDir, 'mesh');
      if (fs.existsSync(meshDir)) {
        const meshMatches = fs.readdirSync(meshDir).filter(f => f.startsWith(prefix) && f.endsWith('.glb')).sort().reverse();
        if (meshMatches.length > 0) glbSourcePath = path.join(meshDir, meshMatches[0]);
      }
    }
  } catch(e) { results.push({ ...item, Status: 'failed', Reason: 'Read output dir: ' + e.message }); continue; }

  if (!glbSourcePath || !fs.existsSync(glbSourcePath)) {
    results.push({ ...item, Status: 'failed', Reason: 'GLB not found: ' + prefix });
    continue;
  }

  try {
    fs.mkdirSync(cardDir, { recursive: true });
    fs.copyFileSync(glbSourcePath, glbDestPath);
  } catch(e) { results.push({ ...item, Status: 'failed', Reason: 'Copy: ' + e.message }); continue; }

  // Copy 3D ref image if exists
  const refPrefix = '3DREF_' + item.CardSlug + '_' + item.Orientation;
  try {
    const refMatches = fs.readdirSync(comfyOutputDir).filter(f => f.startsWith(refPrefix) && f.endsWith('.png')).sort().reverse();
    if (refMatches.length > 0) fs.copyFileSync(path.join(comfyOutputDir, refMatches[0]), path.join(cardDir, item.RefFilename));
  } catch(e) {}

  toRefine.push({ idx, item, glbDestPath: glbDestPath.replace(/\\/g, '/') });
}

if (toRefine.length === 0) {
  console.warn('[Refine] No models to refine');
  return results.map(r => ({ json: r }));
}

// --- Phase 2: Batch refine via single Python process ---
const jobList = toRefine.map(j => j.glbDestPath);
const jobJsonPath = path.join(os.tmpdir(), 'refine_jobs_' + Date.now() + '.json');
const resultJsonPath = path.join(os.tmpdir(), 'refine_results_' + Date.now() + '.json');
fs.writeFileSync(jobJsonPath, JSON.stringify(jobList), 'utf8');

const pyScript = `
import json, sys, gc, os, trimesh

with open(sys.argv[1], 'r') as f:
    jobs = json.load(f)

results = []
for i, glb_path in enumerate(jobs):
    try:
        m = trimesh.load(glb_path)
        if hasattr(m, 'geometry') and isinstance(m.geometry, dict):
            m = trimesh.util.concatenate(list(m.geometry.values()))
        mask = m.nondegenerate_faces()
        if not mask.all():
            m.update_faces(mask)
        m.remove_unreferenced_vertices()
        m.fill_holes()
        if len(m.faces) > 50000:
            try:
                m = m.simplify_quadric_decimation(50000)
            except Exception:
                pass
        try:
            trimesh.smoothing.filter_laplacian(m, iterations=5)
        except Exception:
            pass
        m.fix_normals()
        stats = f'faces={len(m.faces)} verts={len(m.vertices)} watertight={m.is_watertight}'
        m.export(glb_path)
        size_kb = os.path.getsize(glb_path) // 1024
        results.append({'ok': True, 'stats': stats, 'size_kb': size_kb})
        print(f'[{i+1}/{len(jobs)}] OK {os.path.basename(glb_path)} {stats}', flush=True)
    except Exception as e:
        size_kb = os.path.getsize(glb_path) // 1024 if os.path.exists(glb_path) else 0
        results.append({'ok': False, 'error': str(e)[:300], 'size_kb': size_kb})
        print(f'[{i+1}/{len(jobs)}] FAIL {os.path.basename(glb_path)}: {e}', flush=True)
    gc.collect()

with open(sys.argv[2], 'w') as f:
    json.dump(results, f)
`;

const pyScriptPath = path.join(os.tmpdir(), 'refine_batch_' + Date.now() + '.py');
fs.writeFileSync(pyScriptPath, pyScript, 'utf8');

console.warn('[Refine] Running batch Python script for ' + toRefine.length + ' models...');
try {
  // Use async spawn instead of execFileSync to keep event loop alive for heartbeats
  await new Promise((resolve, reject) => {
    const proc = spawn('python', [pyScriptPath, jobJsonPath, resultJsonPath]);
    proc.stdout.on('data', d => { const s = d.toString().trim(); if (s) console.warn(s); });
    proc.stderr.on('data', d => { const s = d.toString().trim(); if (s) console.warn('[Refine stderr] ' + s); });
    proc.on('close', code => { if (code !== 0) reject(new Error('Python exited with code ' + code)); else resolve(); });
    proc.on('error', reject);
  });
} catch(e) {
  console.warn('[Refine] Python script error: ' + e.message.substring(0, 500));
}

// --- Phase 3: Parse results ---
let pyResults = [];
try {
  pyResults = JSON.parse(fs.readFileSync(resultJsonPath, 'utf8'));
} catch(e) {
  console.warn('[Refine] Cannot read results JSON: ' + e.message);
}

for (let i = 0; i < toRefine.length; i++) {
  const { item, glbDestPath } = toRefine[i];
  const pr = pyResults[i];
  if (pr && pr.ok) {
    results.push({ ...item, Status: 'refined', GLBPath: glbDestPath, GLBSizeKB: pr.size_kb, RefinementStats: pr.stats });
  } else {
    const reason = pr ? pr.error : 'No result from Python';
    const sizeKB = pr ? pr.size_kb : 0;
    results.push({ ...item, Status: 'generated', GLBPath: glbDestPath, GLBSizeKB: sizeKB, RefinementError: reason });
  }
}

// Cleanup temp files
try { fs.unlinkSync(jobJsonPath); } catch(e) {}
try { fs.unlinkSync(resultJsonPath); } catch(e) {}
try { fs.unlinkSync(pyScriptPath); } catch(e) {}

const refined = results.filter(r => r.Status === 'refined').length;
const unrefined = results.filter(r => r.Status === 'generated').length;
console.warn('[Refine] Done: ' + refined + ' refined, ' + unrefined + ' unrefined');
return results.map(r => ({ json: r }));

// ============================================================
// Convert GLB to OBJ
// ============================================================
// Batch approach: writes all conversion jobs to a JSON file,
// runs a single Python process to convert all, reads results.
// Uses async spawn (not execFileSync) to keep event loop alive
// for task runner heartbeat pings.
// ============================================================

const fs = require('fs');
const path = require('path');
const { spawn } = require('child_process');
const os = require('os');

const allItems = $input.all().map(item => item.json);
const toConvert = [];
const results = [];

// --- Phase 1: Build conversion job list (JS, fast) ---
for (const item of allItems) {
  if (item.Status !== 'refined' && item.Status !== 'generated') {
    results.push(item);
    continue;
  }
  const glbPath = (item.GLBPath || path.join(item.CardDir, item.GLBFilename)).replace(/\\/g, '/');
  const objPath = path.join(item.CardDir, item.OBJFilename).replace(/\\/g, '/');
  if (!fs.existsSync(glbPath.replace(/\//g, path.sep))) {
    results.push({ ...item, Status: 'failed', Reason: 'GLB not found: ' + glbPath });
    continue;
  }
  toConvert.push({ item, glbPath, objPath });
}

if (toConvert.length === 0) {
  console.warn('[Convert] No models to convert');
  return results.map(r => ({ json: r }));
}

// --- Phase 2: Batch convert via single Python process ---
const jobList = toConvert.map(j => ({ glb: j.glbPath, obj: j.objPath }));
const jobJsonPath = path.join(os.tmpdir(), 'convert_jobs_' + Date.now() + '.json');
const resultJsonPath = path.join(os.tmpdir(), 'convert_results_' + Date.now() + '.json');
fs.writeFileSync(jobJsonPath, JSON.stringify(jobList), 'utf8');

const pyScript = `
import json, sys, gc, os, trimesh

with open(sys.argv[1], 'r') as f:
    jobs = json.load(f)

results = []
for i, job in enumerate(jobs):
    glb_path, obj_path = job['glb'], job['obj']
    try:
        m = trimesh.load(glb_path)
        if hasattr(m, 'geometry') and isinstance(m.geometry, dict):
            m = trimesh.util.concatenate(list(m.geometry.values()))
        m.export(obj_path)
        glb_kb = os.path.getsize(glb_path) // 1024
        obj_kb = os.path.getsize(obj_path) // 1024
        results.append({'ok': True, 'glb_kb': glb_kb, 'obj_kb': obj_kb})
        print(f'[{i+1}/{len(jobs)}] OK {os.path.basename(glb_path)} -> {obj_kb}KB OBJ', flush=True)
    except Exception as e:
        results.append({'ok': False, 'error': str(e)[:300]})
        print(f'[{i+1}/{len(jobs)}] FAIL {os.path.basename(glb_path)}: {e}', flush=True)
    gc.collect()

with open(sys.argv[2], 'w') as f:
    json.dump(results, f)
`;

const pyScriptPath = path.join(os.tmpdir(), 'convert_batch_' + Date.now() + '.py');
fs.writeFileSync(pyScriptPath, pyScript, 'utf8');

console.warn('[Convert] Running batch Python script for ' + toConvert.length + ' models...');
try {
  // Use async spawn instead of execFileSync to keep event loop alive for heartbeats
  await new Promise((resolve, reject) => {
    const proc = spawn('python', [pyScriptPath, jobJsonPath, resultJsonPath]);
    proc.stdout.on('data', d => { const s = d.toString().trim(); if (s) console.warn(s); });
    proc.stderr.on('data', d => { const s = d.toString().trim(); if (s) console.warn('[Convert stderr] ' + s); });
    proc.on('close', code => { if (code !== 0) reject(new Error('Python exited with code ' + code)); else resolve(); });
    proc.on('error', reject);
  });
} catch(e) {
  console.warn('[Convert] Python script error: ' + e.message.substring(0, 500));
}

// --- Phase 3: Parse results ---
let pyResults = [];
try {
  pyResults = JSON.parse(fs.readFileSync(resultJsonPath, 'utf8'));
} catch(e) {
  console.warn('[Convert] Cannot read results JSON: ' + e.message);
}

for (let i = 0; i < toConvert.length; i++) {
  const { item, glbPath, objPath } = toConvert[i];
  const pr = pyResults[i];
  if (pr && pr.ok) {
    results.push({ ...item, Status: 'completed', GLBPath: glbPath, OBJPath: objPath, GLBSizeKB: pr.glb_kb, OBJSizeKB: pr.obj_kb });
  } else {
    const reason = pr ? pr.error : 'No result from Python';
    results.push({ ...item, Status: 'partial', GLBPath: glbPath, Reason: 'OBJ: ' + reason });
  }
}

// Cleanup
try { fs.unlinkSync(jobJsonPath); } catch(e) {}
try { fs.unlinkSync(resultJsonPath); } catch(e) {}
try { fs.unlinkSync(pyScriptPath); } catch(e) {}

const ok = results.filter(r => r.Status === 'completed').length;
const partial = results.filter(r => r.Status === 'partial').length;
console.warn('[Convert] Done: ' + ok + ' completed, ' + partial + ' partial');
return results.map(r => ({ json: r }));

// ============================================================
// Report Results
// ============================================================

const allItems = $input.all().map(item => item.json);

const completed = allItems.filter(i => i.Status === 'completed');
const partial   = allItems.filter(i => i.Status === 'partial');
const failed    = allItems.filter(i => i.Status === 'failed');
const timeout   = allItems.filter(i => i.Status === 'timeout');

// Count by generation method
const byMethod = {};
for (const item of allItems) {
  const method = item.GenerationMethod || 'unknown';
  byMethod[method] = (byMethod[method] || 0) + 1;
}

const summary = {
  Total: allItems.length,
  Completed: completed.length,
  Partial: partial.length,
  Failed: failed.length,
  Timeout: timeout.length,
  ByMethod: byMethod,
  Details: allItems.map(i => ({
    Card: i.CardName,
    Orientation: i.Orientation,
    Status: i.Status,
    Method: i.GenerationMethod || '',
    GLBPath: i.GLBPath || '',
    OBJPath: i.OBJPath || '',
    GLBSizeKB: i.GLBSizeKB || 0,
    OBJSizeKB: i.OBJSizeKB || 0,
    Reason: i.Reason || ''
  }))
};

console.warn('=== 3D Object Generation Complete ===');
console.warn('Completed: ' + completed.length + '  Partial: ' + partial.length + '  Failed: ' + failed.length + '  Timeout: ' + timeout.length);
console.warn('By method: ' + JSON.stringify(byMethod));

if (failed.length > 0) {
  console.warn('Failed cards:');
  for (const f of failed) {
    console.warn('  - ' + f.CardName + ' ' + f.Orientation + ' (' + (f.GenerationMethod || '') + '): ' + (f.Reason || 'unknown'));
  }
}

return [{ json: summary }];
